INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-acfc4025-moex-00082', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「從月鳳和我的演講之後，班上又加了一種讀書方法——演說。人人爭著 說。我們打招呼、看衣服、讀文法、塗漫畫、改小說、吃糖果、切蛋糕、 泡茶水，然後一國一國的文化開始上演。那教室，像極了一座流動的旋轉 馬。每一個人騎在一匹響著音樂的馬上，高高低低的旋轉不停。」 根據上文，下列選項最接近教室學習氣氛的描述是：', '["多元學習樂無窮", "循序漸進效率高", "各憑本事爭出頭", "獨善其身做學問"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00083', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「蛋餅總是連結著我每一天生產力的開端，從前連結上學，後來連結上班。 粉漿蛋餅登場的時候，是我成年的開始，學校裡有聰慧的老師，有知心的 同學，有戀慕的對象，面對模糊的未來卻懷抱著明確的希望。後來再吃到 的蛋餅，連結遲到一分鐘扣五十元的打卡，還有輸入整頁資料卻當機的電 腦視窗。」 根據上文，下列選項對於蛋餅滋味的敘述何者正確？', '["不同的蛋餅卻有相似的滋味", "來自於人生不同階段的體悟", "從青春到成年的豐富與飽足感", "表達人生無常的循環與宿命感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00084', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「『指南』激不激發『欲遊者』之夢？若然，那指南豈不如同扣人心弦的 散文或遊記？是的，好的指南常是好的散文寫作，但不多。有的指南，太 感情用事，作者自己沉醉其所旅遊之地，說得天花亂墜，而展書者越讀越 生疑懼，這樣的指南，亦不成功。這樣的書，像是描寫天堂。」 根據上文，最符合本文旨趣的是：', '["好的旅遊指南應吸引人，但是也要顧及真實面向", "旅遊指南不能理性書寫，將使內容流於矯情浮濫", "旅遊指南與旅行文學的差異在於前者更強調客觀", "有主見的旅者非但不依旅遊指南甚至更擅於質疑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00085', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「『引紅海救死海』的構想早在一個多世紀前就提出，由於技術問題，加 上以色列、巴勒斯坦是世仇，戰爭不斷，無法合作。如今為了水，化干戈 為玉帛。依照計畫，以色列將從最大水庫金內瑞湖釋出更多水供應約旦， 並把淡化後的水賣給巴勒斯坦。約旦南部紅海的港市阿卡巴也將興建淡化 廠，把水分享各方；鹹水則透過輸水管，北送死海。」 根據上文，下列選項何者正確？', '["死海周邊各國為爭奪死海戰火不斷", "約旦以輸水管將紅海鹹水引入死海", "約旦擬將淡化海水的技術賣給鄰國", "以色列因世仇問題拒絕與鄰國合作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00086', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「這時代，很多人感嘆閱讀的人變少了，不過現代生活的確不鼓勵人閱讀， 閱讀帶來的思考很可能讓你更不容易融入這社會的運作裡。現代人有他一 定運作的速度，若不在速度的螺旋上，就是在一連串的雜訊干擾中焦慮地 放空，但閱讀攔截了這種生活形式，閱讀這行為雖然低調，但根本性地反 抗了現代生活推崇的理想形式。」 根據上文，下列選項最符合文意的是：', '["閱讀賦予我們反省當代生活的節奏", "閱讀的焦慮感增加現代生活的困境", "快速閱讀有利於掌握社會的運作邏輯", "影音媒體流行是現代生活的理想形式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00087', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '一位擅長以客家花布創作的藝術家說到：「鮮豔的印花圖騰具有濃郁的臺 灣色彩，不能將它視為單純的文化象徵，反而是一種追尋自我認同、建立 對話的媒介。使用花布作為素材是為了建立當代藝術與東方傳統的對話， 透過自身的文化探索，突顯出全球化與地方性的關係。」 根據上文，下列選項何者最接近文意？', '["強調當代藝術是一種文化的對話，並不單指一種文化", "藝術創作不需要使用象徵的符號，關鍵在於不期而遇", "使用客家花布創作是為了突顯臺灣文化主體優越性，讓世界看見臺灣", "東西方藝術有著截然不同的特色元素，鮮豔的美感是當代藝術的精髓"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00088', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「朱老師一輩子編報教書，筆耕不輟，退休後還到報社做事排遣時間。教我 們《新聞英語》那幾年他是報社總編輯。一天，我去看望老師，報館一位見 習生也在，他說最想靠寫作維生，向老師討教。老師說沒什麼好教的，寫作 只靠用功、勤奮，別的不重要。那時我心想老師是在敷衍那位見習生。離開 學堂我編報筆耕幾十年，回想老師那句話，真是醍醐灌頂，點滴在心頭。」 作者回想老師的話感覺「醍醐灌頂」，最主要的原因是：', '["在職場中能保持工作熱情最難能可貴", "個人多年職場的經歷驗證了老師的話", "後輩真的以用功勤奮實現了早年心願", "維持熱情的良方原來是懂得經驗分享"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00089', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「《生命中不能承受之輕》書中問著：『她終於找回了當年失去的父母嗎？ 她終於找回了她從未有過的孩子嗎？』幸運的是，你有一對兒女；更幸運 的是，因為這一對兒女，身上的層層糾結到你為止；最為幸運的是，經由 兒子與女兒，你終於找回……久遠以前失去的東西。」 根據上文，下列選項何者最切近文中的「你」看待兒女的態度？', '["上天的恩賜", "終老的依靠", "私有的財產", "親情的依存"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00090', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「老樹啊！你以濃鬱的蔭涼與市民朝夕相處，你以門神之姿捍衛這座舊城 的傳統。」 根據上文，下列選項最符合舊城老樹「門神」特質的是：', '["質樸親切", "輕盈靈巧", "優雅柔美", "雄偉挺拔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00091', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「沒有人能事先預見所有的危機，但有個方法可以降低損害，就是避免單 點故障。要是許多事情都仰賴某件事才能運作，而那件事出問題了，就會 成為嚴重的災難。」 下列說明，最能表達此段文字主旨的是：', '["分散風險", "提前布署", "慎勿落單", "沉著鎮定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL)
